// RAKITRAKATRA MINIMAP - FIXED v1.0
(function(){
  var R = window.Rakitrakatra || {};
  if(typeof window.Rakitrakatra === 'undefined') window.Rakitrakatra = R;
  
  R.Minimap = function(kianja, opts){
    opts = opts || {};
    this.kianja = kianja;
    this.x = opts.x || 10;
    this.y = opts.y || 10;
    this.w = opts.sakany || 150;
    this.h = opts.haavony || 150;
    this.scale = opts.scale || 0.1;
    this.fog = opts.fog !== false;
    this.revealed = [];
    this.canvas = document.createElement('canvas');
    this.canvas.width = this.w;
    this.canvas.height = this.h;
    this.ctx = this.canvas.getContext('2d');
    
    if(kianja && kianja.zavatra) kianja.zavatra.push(this);
    console.log('✅ Minimap loaded');
  };
  
  R.Minimap.prototype.reveal = function(x,y,r){
    this.revealed.push({x:x, y:y, r:r||50});
  };
  
  R.Minimap.prototype.havaozy = function(dt){};
  
  R.Minimap.prototype.soraty = function(ctx){
    if(!ctx) return;
    var c = this.ctx;
    c.fillStyle = 'rgba(0,0,0,0.8)';
    c.fillRect(0,0,this.w,this.h);
    
    // Draw objects
    if(this.kianja && this.kianja.zavatra){
      var self=this;
      this.kianja.zavatra.forEach(function(obj){
        if(obj === self) return;
        if(typeof obj.x !== 'undefined'){
          var mx = obj.x * self.scale;
          var my = obj.y * self.scale;
          c.fillStyle = obj.loko || '#ff1493';
          c.fillRect(mx-1, my-1, 3, 3);
        }
      });
    }
    
    // Draw to main ctx
    ctx.save();
    ctx.globalAlpha = 0.9;
    ctx.drawImage(this.canvas, this.x, this.y);
    ctx.strokeStyle = '#00ffff';
    ctx.lineWidth = 2;
    ctx.strokeRect(this.x, this.y, this.w, this.h);
    ctx.restore();
  };
  
  console.log('✅ rakitrakatra.minimap.min.js FIXED');
})();
